-- Exercise YouTube reference links — batch 3 (parts 1, 6, 7, 9).
-- IDEMPOTENT. Generated by scripts/generate-204-exercise-youtube-links.mjs
-- Matches by exercise slug (portable across environments). Falls back to name when slug unknown.
-- Merges embeddable watch URLs into media_library.clinical_or_sport_science_references.

-- 10-Yard Sprint (10-yard-sprint)
UPDATE coaching.exercise e
SET
  media_library = jsonb_set(
    COALESCE(e.media_library, '{}'::jsonb),
    '{clinical_or_sport_science_references}',
    COALESCE(
      (
        SELECT jsonb_agg(elem ORDER BY elem)
        FROM (
          SELECT DISTINCT elem
          FROM (
            SELECT jsonb_array_elements_text(
              COALESCE(e.media_library->'clinical_or_sport_science_references', '[]'::jsonb)
            ) AS elem
            UNION ALL
            SELECT unnest(ARRAY['https://www.youtube.com/watch?v=mATMYLiKa_0', 'https://www.youtube.com/watch?v=d9ZC-vTABCw', 'https://www.youtube.com/watch?v=00lM8-a2o3Y', 'https://www.youtube.com/watch?v=3d8W16av094']::text[]) AS elem
          ) combined
          WHERE elem IS NOT NULL AND btrim(elem) <> ''
            AND elem ~* '^https?://(www\.)?(youtube\.com/watch\?v=|youtu\.be/|youtube\.com/shorts/|youtube\.com/embed/)'
        ) deduped
      ),
      '[]'::jsonb
    ),
    true
  ),
  updated_at = now()
WHERE e.slug = '10-yard-sprint';

