  media_library = jsonb_set(
    COALESCE(e.media_library, '{}'::jsonb),
    '{clinical_or_sport_science_references}',
    COALESCE(
      (
        SELECT jsonb_agg(elem ORDER BY elem)
        FROM (
          SELECT DISTINCT elem
          FROM (
            SELECT jsonb_array_elements_text(
              COALESCE(e.media_library->'clinical_or_sport_science_references', '[]'::jsonb)
            ) AS elem
            UNION ALL
            SELECT unnest(ARRAY['https://www.youtube.com/watch?v=aDG5m7BRhSQ', 'https://www.youtube.com/watch?v=qAiWa5OkRak', 'https://www.youtube.com/watch?v=P9Hxs237fVQ', 'https://www.youtube.com/watch?v=qNPVjehTyKA', 'https://www.youtube.com/watch?v=I5CmIUg9QKg']::text[]) AS elem
          ) combined
          WHERE elem IS NOT NULL AND btrim(elem) <> ''
            AND elem ~* '^https?://(www\.)?(youtube\.com/watch\?v=|youtu\.be/|youtube\.com/shorts/|youtube\.com/embed/)'
        ) deduped
      ),
      '[]'::jsonb
    ),
    true
  ),
  updated_at = now()
WHERE e.slug = 'tempo-bodyweight-squat';

